function resolveSpeechLocale(language = "English") {
  const normalized = String(language || "").trim().toLowerCase();
  if (normalized === "isizulu") return "zu-ZA";
  if (normalized === "afrikaans") return "af-ZA";
  if (normalized === "isixhosa") return "xh-ZA";
  if (normalized === "sesotho") return "st-ZA";
  if (normalized === "setswana") return "tn-ZA";
  if (normalized === "french") return "fr-FR";
  if (normalized === "portuguese") return "pt-PT";
  return "en-ZA";
}

function resolveTeacherVoice(voices = [], selectedVoiceName = "", language = "English") {
  const preferredLocale = resolveSpeechLocale(language).toLowerCase();
  const preferredLanguageCode = preferredLocale.split("-")[0];
  return voices.find((voice) => voice.name === selectedVoiceName)
    || voices.find((voice) => String(voice.lang || "").toLowerCase() === preferredLocale)
    || voices.find((voice) => String(voice.lang || "").toLowerCase().startsWith(`${preferredLanguageCode}-`))
    || voices.find((voice) => /female|woman|zira|aria|samantha|google uk english female|michelle|serena/i.test(voice.name))
    || voices.find((voice) => /google|microsoft|natural|english/i.test(voice.name))
    || voices[0]
    || null;
}

function getSpeechRecognitionConstructor() {
  if (typeof window === "undefined") return null;
  return window.SpeechRecognition || window.webkitSpeechRecognition || null;
}

function normalizeCollaborationRoomId(value = "") {
  const cleaned = String(value || "").trim();
  return /^[A-Za-z0-9_-]{8,80}$/.test(cleaned) ? cleaned : "";
}

function loadStoredRoomInviteId() {
  if (typeof window === "undefined") return "";
  return normalizeCollaborationRoomId(window.localStorage.getItem(ROOM_INVITE_STORAGE_KEY) || "");
}

function loadDismissedRoomInviteIds(email = "") {
  if (typeof window === "undefined") return [];
  try {
    const normalizedEmail = normalizeHistoryOwnerEmail(email || window.localStorage.getItem(AUTH_EMAIL_KEY) || "") || "__guest__";
    const parsed = JSON.parse(window.localStorage.getItem(ROOM_INVITE_DISMISSALS_STORAGE_KEY) || "{}");
    const values = Array.isArray(parsed)
      ? parsed
      : parsed && typeof parsed === "object" && Array.isArray(parsed[normalizedEmail])
        ? parsed[normalizedEmail]
        : [];
    return Array.from(new Set(values.map((item) => normalizeCollaborationRoomId(item)).filter(Boolean)));
  } catch {
    return [];
  }
}

function parseRoomInviteIdFromLocation() {
  if (typeof window === "undefined") return "";
  try {
    const searchParams = new URLSearchParams(window.location.search || "");
    const searchInviteId = normalizeCollaborationRoomId(searchParams.get("invite") || searchParams.get("room") || "");
    if (searchInviteId) return searchInviteId;
  } catch {
    // Ignore malformed search params and continue to hash parsing.
  }
  const rawHash = (window.location.hash || "").replace(/^#/, "");
  if (!rawHash) return "";
  const hashParams = new URLSearchParams(rawHash);
  return normalizeCollaborationRoomId(hashParams.get("room") || hashParams.get("invite") || rawHash);
}

function shouldFocusCollaborationReplyFromLocation() {
  if (typeof window === "undefined") return false;
  try {
    const searchParams = new URLSearchParams(window.location.search || "");
    const searchValue = (searchParams.get("reply") || "").trim().toLowerCase();
    if (["1", "true", "reply", "yes"].includes(searchValue)) return true;
  } catch {
    // Ignore malformed search params and continue to hash parsing.
  }
  const rawHash = (window.location.hash || "").replace(/^#/, "");
  if (!rawHash) return false;
  const hashParams = new URLSearchParams(rawHash);
  const hashValue = (hashParams.get("reply") || "").trim().toLowerCase();
  return ["1", "true", "reply", "yes"].includes(hashValue);
}

function buildCollaborationReplyPath(roomId = "") {
  const normalizedRoomId = normalizeCollaborationRoomId(roomId);
  if (!normalizedRoomId) return "/app/collaboration";
  return `/app/collaboration?room=${encodeURIComponent(normalizedRoomId)}&reply=1`;
}

function buildPublicSupportPlaceholderEmail(seed = "") {
  const cleanedSeed = String(seed || "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "")
    .slice(0, 24);
  return `guest+${cleanedSeed || Date.now()}@mabaso.ai`;
}

function rememberExplicitProtectedPreviewPath(path = "") {
  if (typeof window === "undefined") return "";
  const normalized = normalizeRoutePath(path);
  if (normalized.startsWith("/app/")) {
    window.sessionStorage.setItem(EXPLICIT_PROTECTED_PREVIEW_PATH_KEY, normalized);
    return normalized;
  }
  window.sessionStorage.removeItem(EXPLICIT_PROTECTED_PREVIEW_PATH_KEY);
  return "";
}

function readExplicitProtectedPreviewPath() {
  if (typeof window === "undefined") return "";
  return normalizeRoutePath(window.sessionStorage.getItem(EXPLICIT_PROTECTED_PREVIEW_PATH_KEY) || "");
}

function consumeExplicitProtectedPreviewPath() {
  const normalized = readExplicitProtectedPreviewPath();
  if (typeof window !== "undefined") {
    window.sessionStorage.removeItem(EXPLICIT_PROTECTED_PREVIEW_PATH_KEY);
  }
  return normalized;
}

