function isTeacherSpeechNoise(text = "") {
  const normalizedText = String(text || "").replace(/\s+/g, " ").trim().toLowerCase();
  if (!normalizedText) return true;
  const wordCount = (normalizedText.match(/\b[\w'-]+\b/g) || []).length;
  const hasSlideMarker = /\b(?:slide|page)\s*\d{1,3}\b/.test(normalizedText);
  const hasYear = /\b20\d{2}\b/.test(normalizedText);
  const hasInstitution = /durban university of technology|university of technology|department of|faculty of|school of/.test(normalizedText);
  const hasAdminPhrase = /copyright|all rights reserved|confidential|lecture slides|slide deck|page number/.test(normalizedText);
  if (/^(?:slide|page)\s*\d{1,3}$/.test(normalizedText)) return true;
  if (/^\d{1,3}$/.test(normalizedText) || /^20\d{2}$/.test(normalizedText)) return true;
  if (hasAdminPhrase) return true;
  if (hasSlideMarker && (hasYear || hasInstitution || wordCount <= 6)) return true;
  if (hasInstitution && (hasYear || wordCount <= 14)) return true;
  if (hasYear && wordCount <= 5) return true;
  return false;
}

function buildSpeechChunks(text = "", maxLength = 420) {
  const normalizedText = String(text || "")
    .replace(/[`*_#>|]+/g, " ")
    .replace(/[•◆◇▪▫]/g, ". ")
    .replace(/[–—]/g, "-")
    .replace(/\s+/g, " ")
    .trim();
  if (!normalizedText) return [];
  const sentences = normalizedText.match(/[^.!?]+[.!?]*/g) || [normalizedText];
  const chunks = [];
  let current = "";
  sentences.forEach((sentence) => {
    const cleanSentence = sentence.replace(/^\s*(?:slide|page)\s*\d{1,3}\s*[:\-]?\s*/i, "").trim();
    if (!cleanSentence) return;
    if (isTeacherSpeechNoise(cleanSentence)) return;
    if ((current.length + cleanSentence.length + 1) <= maxLength) {
      current = [current, cleanSentence].filter(Boolean).join(" ");
      return;
    }
    if (current) chunks.push(current);
    if (cleanSentence.length <= maxLength) {
      current = cleanSentence;
      return;
    }
    for (let start = 0; start < cleanSentence.length; start += maxLength) {
      chunks.push(cleanSentence.slice(start, start + maxLength).trim());
    }
    current = "";
  });
  if (current) chunks.push(current);
  return chunks;
}

function getTeacherSpeechRate(pace = "balanced", mode = "lesson") {
  const normalizedPace = String(pace || "balanced").toLowerCase();
  if (normalizedPace === "slow") return mode === "answer" ? 0.86 : 0.82;
  if (normalizedPace === "fast") return mode === "answer" ? 0.98 : 0.94;
  return mode === "answer" ? 0.92 : 0.88;
}

function formatTutorTimestampLabel(value = "") {
  if (!value) return "--:--";
  try {
    return new Date(value).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
  } catch {
    return "--:--";
  }
}

function getNetworkQualityDescriptor(connection) {
  if (!connection) return "Stable";
  const effectiveType = String(connection.effectiveType || "").toLowerCase();
  const downlink = Number(connection.downlink || 0);
  if (effectiveType.includes("slow-2g") || effectiveType.includes("2g")) return "Weak";
  if (effectiveType.includes("3g") || downlink < 2) return "Fair";
  if (effectiveType.includes("4g") || downlink >= 5) return "Strong";
  return "Stable";
}

const realtimeTutorVoiceOptions = [
  { value: "marin", label: "Marin" },
  { value: "cedar", label: "Cedar" },
  { value: "alloy", label: "Alloy" },
  { value: "ash", label: "Ash" },
  { value: "ballad", label: "Ballad" },
  { value: "coral", label: "Coral" },
  { value: "echo", label: "Echo" },
  { value: "sage", label: "Sage" },
  { value: "shimmer", label: "Shimmer" },
  { value: "verse", label: "Verse" },
];

function normalizeRealtimeTutorVoiceId(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  const directMatch = realtimeTutorVoiceOptions.find((option) => option.value === normalized);
  if (directMatch) return directMatch.value;
  const partialMatch = realtimeTutorVoiceOptions.find((option) => normalized.includes(option.value));
  if (partialMatch) return partialMatch.value;
  return "marin";
}

const defaultPodcastSpeakerProfiles = [
  {
    key: "professor",
    name: "Professor",
    role: "Professor / teacher",
    voice: "marin",
  },
  {
    key: "student_1",
    name: "Student 1",
    role: "Student",
    voice: "coral",
  },
  {
    key: "student_2",
    name: "Student 2",
    role: "Student",
    voice: "echo",
  },
];

function createDefaultPodcastSpeakerProfiles() {
  return defaultPodcastSpeakerProfiles.map((profile) => ({ ...profile }));
}

function normalizePodcastSpeakerProfiles(value, speakerCount = 2) {
  const requestedProfiles = Array.isArray(value) ? value : [];
  const requestedByKey = new Map(
    requestedProfiles
      .filter((profile) => profile && typeof profile === "object")
      .map((profile) => [String(profile.key || "").trim().toLowerCase(), profile]),
  );
  const normalizedCount = Number(speakerCount || 2) >= 3 ? 3 : 2;
  return defaultPodcastSpeakerProfiles.slice(0, normalizedCount).map((defaultProfile) => {
    const requested = requestedByKey.get(defaultProfile.key) || {};
    const nextName = String(requested.name || "").trim();
    return {
      ...defaultProfile,
      name: defaultProfile.key === "professor" ? "Professor" : (nextName || defaultProfile.name),
      role: defaultProfile.role,
      voice: normalizeRealtimeTutorVoiceId(requested.voice || defaultProfile.voice),
    };
  });
}

function resolveRealtimeTutorLanguageHint(language = "English") {
  const normalized = String(language || "").trim().toLowerCase();
  if (normalized === "isizulu") return "zu";
  if (normalized === "afrikaans") return "af";
  if (normalized === "isixhosa") return "xh";
  if (normalized === "sesotho") return "st";
  if (normalized === "setswana") return "tn";
  if (normalized === "french") return "fr";
  if (normalized === "portuguese") return "pt";
  return "en";
}

function resolveRealtimeTutorPreviewTarget(text = "") {
  const normalized = String(text || "").toLowerCase();
  if (!normalized) return "";
  if (/(worked example|example\s+\d|step-by-step explanation|step by step explanation)/.test(normalized)) return "examples";
  if (/transcript|what you said|lecture transcript/.test(normalized)) return "transcript";
  if (/study guide|summary|formula|key concept|definition/.test(normalized)) return "guide";
  return "";
}

function extractRealtimeTutorTextFromResponseEvent(event) {
  if (!event || typeof event !== "object") return "";
  const response = event.response && typeof event.response === "object" ? event.response : null;
  if (!response || !Array.isArray(response.output)) return "";
  const parts = [];
  response.output.forEach((item) => {
    if (!item || typeof item !== "object") return;
    if (typeof item.text === "string" && item.text.trim()) parts.push(item.text.trim());
    const contentParts = Array.isArray(item.content) ? item.content : [];
    contentParts.forEach((part) => {
      if (!part || typeof part !== "object") return;
      if (typeof part.text === "string" && part.text.trim()) parts.push(part.text.trim());
      if (typeof part.transcript === "string" && part.transcript.trim()) parts.push(part.transcript.trim());
      if (typeof part.audio_transcript === "string" && part.audio_transcript.trim()) parts.push(part.audio_transcript.trim());
    });
  });
  return parts.join(" ").replace(/\s+/g, " ").trim();
}

function getPresentationVisualTypeLabel(value) {
  const normalized = (value || "cluster").toLowerCase();
  if (normalized === "flow") return "Flow";
  if (normalized === "comparison") return "Comparison";
  if (normalized === "timeline") return "Timeline";
  if (normalized === "cycle") return "Cycle";
  if (normalized === "formula") return "Formula";
  if (normalized === "components") return "Components";
  if (normalized === "table") return "Table";
  if (normalized === "chart") return "Chart";
  if (normalized === "graph") return "Graph";
  if (normalized === "photo") return "Photo";
  if (normalized === "closing") return "Closing";
  return "Cluster";
}

function resolveInitialPublicPage() {
  if (typeof window === "undefined") return "auth";
  return window.location.pathname === PUBLIC_TERMS_PATH ? "terms" : "auth";
}

