  const [teacherSessionStartedAt, setTeacherSessionStartedAt] = useState("");
  const [teacherSessionElapsedSeconds, setTeacherSessionElapsedSeconds] = useState(0);
  const [teacherNetworkQuality, setTeacherNetworkQuality] = useState(() => (typeof navigator !== "undefined" && navigator.onLine ? "Strong" : "Offline"));
  const [isTeacherMuted, setIsTeacherMuted] = useState(false);
  const [teacherRealtimeConnectionState, setTeacherRealtimeConnectionState] = useState(TEACHER_REALTIME_CONNECTION_STATES.IDLE);
  const [isTeacherRealtimeConnecting, setIsTeacherRealtimeConnecting] = useState(false);
  const [isTeacherRealtimeConnected, setIsTeacherRealtimeConnected] = useState(false);
  const [teacherRealtimeModel, setTeacherRealtimeModel] = useState("");
  const [teacherRealtimeRemainingSeconds, setTeacherRealtimeRemainingSeconds] = useState(300);
  const [teacherRealtimeSessionCapSeconds, setTeacherRealtimeSessionCapSeconds] = useState(300);
  const [isTeacherRealtimeMicActive, setIsTeacherRealtimeMicActive] = useState(false);
  const [isTutorCameraOn, setIsTutorCameraOn] = useState(false);
  const [isTutorScreenSharing, setIsTutorScreenSharing] = useState(false);
  const [activeTeacherSegmentIndex, setActiveTeacherSegmentIndex] = useState(-1);
  const [isTeacherPlaying, setIsTeacherPlaying] = useState(false);
  const [isTeacherPaused, setIsTeacherPaused] = useState(false);
  const [isTeacherListening, setIsTeacherListening] = useState(false);
  const [isTeacherQuestionLoading, setIsTeacherQuestionLoading] = useState(false);
  const [isTeacherAnswering, setIsTeacherAnswering] = useState(false);
  const [teacherQuestionDraft, setTeacherQuestionDraft] = useState("");
  const [teacherQuestionAnswer, setTeacherQuestionAnswer] = useState("");
  const [teacherQuestionStatus, setTeacherQuestionStatus] = useState("");
  const [browserVoiceDraft, setBrowserVoiceDraft] = useState("");
  const [browserVoiceMessages, setBrowserVoiceMessages] = useState([]);
  const [browserVoiceStatus, setBrowserVoiceStatus] = useState("Use your microphone or type a question. This page answers from the lecture already loaded in your browser.");
  const [isBrowserVoiceListening, setIsBrowserVoiceListening] = useState(false);
  const [isBrowserVoiceSpeaking, setIsBrowserVoiceSpeaking] = useState(false);

  const persistPostAuthRedirectPath = (path = "") => {
    const normalized = normalizePostAuthRedirectPath(path);
    pendingAuthRedirectPathRef.current = normalized;
    if (typeof window !== "undefined") {
      if (normalized) {
        window.localStorage.setItem(AUTH_REDIRECT_PATH_KEY, normalized);
      } else {
        window.localStorage.removeItem(AUTH_REDIRECT_PATH_KEY);
      }
    }
    return normalized;
  };

  const readPendingPostAuthRedirectPath = () => normalizePostAuthRedirectPath(
    pendingAuthRedirectPathRef.current
      || (typeof window !== "undefined" ? window.localStorage.getItem(AUTH_REDIRECT_PATH_KEY) || "" : ""),
  );

  const consumePendingPostAuthRedirectPath = () => {
    const targetPath = readPendingPostAuthRedirectPath();
    persistPostAuthRedirectPath("");
    return targetPath;
  };

  const persistPendingRoomInviteId = (roomId = "") => {
    const normalized = normalizeCollaborationRoomId(roomId);
    pendingRoomInviteIdRef.current = normalized;
    if (typeof window !== "undefined") {
      if (normalized) {
        window.localStorage.setItem(ROOM_INVITE_STORAGE_KEY, normalized);
      } else {
        window.localStorage.removeItem(ROOM_INVITE_STORAGE_KEY);
      }
    }
    return normalized;
  };

  const getCollaborationStorageEmail = (emailOverride = "") => (
    normalizeHistoryOwnerEmail(emailOverride || authEmail || authEmailInput || (typeof window !== "undefined" ? window.localStorage.getItem(AUTH_EMAIL_KEY) || "" : "")) || "__guest__"
  );

  const loadActiveCollaborationRoomId = (emailOverride = "") => {
    if (typeof window === "undefined") return "";
    try {
      const parsed = JSON.parse(window.localStorage.getItem(ACTIVE_COLLABORATION_ROOM_STORAGE_KEY) || "{}");
      const ownerKey = getCollaborationStorageEmail(emailOverride);
      if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
        return normalizeCollaborationRoomId(parsed[ownerKey] || "");
      }
      return normalizeCollaborationRoomId(String(parsed || ""));
    } catch {
      return "";
    }
  };

  const persistActiveCollaborationRoomId = (roomId = "", emailOverride = "") => {
    const normalized = normalizeCollaborationRoomId(roomId);
    if (typeof window !== "undefined") {
      const ownerKey = getCollaborationStorageEmail(emailOverride);
      let storedMap = {};
      try {
        const parsed = JSON.parse(window.localStorage.getItem(ACTIVE_COLLABORATION_ROOM_STORAGE_KEY) || "{}");
        if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) storedMap = parsed;
      } catch {
        storedMap = {};
      }
      if (normalized) {
        window.localStorage.setItem(ACTIVE_COLLABORATION_ROOM_STORAGE_KEY, JSON.stringify({ ...storedMap, [ownerKey]: normalized }));
      } else {
        delete storedMap[ownerKey];
        window.localStorage.setItem(ACTIVE_COLLABORATION_ROOM_STORAGE_KEY, JSON.stringify(storedMap));
      }
    }
    return normalized;
  };

  const persistDismissedRoomInviteList = (roomIds = [], emailOverride = "") => {
    const normalized = Array.from(new Set((roomIds || []).map((item) => normalizeCollaborationRoomId(item)).filter(Boolean)));
    const normalizedEmail = normalizeHistoryOwnerEmail(emailOverride || authEmail || authEmailInput || "") || "__guest__";
    setDismissedRoomInviteIds(normalized);
    if (typeof window !== "undefined") {
      let storedMap = {};
      try {
        const parsed = JSON.parse(window.localStorage.getItem(ROOM_INVITE_DISMISSALS_STORAGE_KEY) || "{}");
        if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
          storedMap = parsed;
        }
      } catch {
        storedMap = {};
      }
      window.localStorage.setItem(
        ROOM_INVITE_DISMISSALS_STORAGE_KEY,
        JSON.stringify({ ...storedMap, [normalizedEmail]: normalized }),
      );
    }
    return normalized;
  };

  const completePendingPostAuthRedirect = (sessionMode = "user") => {
    const targetPath = readPendingPostAuthRedirectPath();
    if (!targetPath) return false;

    const normalizedSessionMode = sessionMode === "admin" ? "admin" : "user";
    const routeInfo = resolveEnterpriseRoute(targetPath);
    if (normalizedSessionMode === "admin") {
      if (targetPath !== "/admin/dashboard") return false;
      setCurrentPage("admin");
      navigateToPath(targetPath, { replace: true });
      consumePendingPostAuthRedirectPath();
      return true;
    }

    const routedPage = resolveCurrentPageFromRoute(targetPath);
    if (!routeInfo.protectedWorkspaceRoute || !routedPage) return false;
    setCurrentPage(routedPage);
    navigateToPath(targetPath, { replace: true });
    consumePendingPostAuthRedirectPath();
    return true;
  };

  const navigateToPath = (path, { replace = false } = {}) => {
    const normalized = normalizeRoutePath(path);
    const currentPath = typeof window !== "undefined" ? window.location.pathname : browserPath;
    const pathChanged = currentPath !== normalized;
    if (typeof window !== "undefined" && pathChanged) {
      window.history[replace ? "replaceState" : "pushState"]({}, "", normalized);
    }
    setBrowserPath((current) => (current === normalized ? current : normalized));
    setPublicPage((current) => {
      const nextPublicPage = normalized === PUBLIC_TERMS_PATH ? "terms" : "auth";
      return current === nextPublicPage ? current : nextPublicPage;
    });
    if (pathChanged && typeof window !== "undefined") {
      window.requestAnimationFrame(() => {
        window.scrollTo({ top: 0, left: 0, behavior: "auto" });
      });
    }
  };

  const updateReportConfigField = (field, value) => {
    setReportConfig((current) => ({ ...current, [field]: value }));
  };

  const toggleReportFeature = (featureKey) => {
    setReportConfig((current) => ({
      ...current,
      features: { ...current.features, [featureKey]: !current.features?.[featureKey] },
    }));
  };

  const openReportConfiguration = () => {
    if (!reportConfig.reportTitle.trim()) {
      const suggestedTitle = extractHistoryTitle(summary || transcript || lectureNotes || lectureSlides || pastQuestionPapers, workspaceFileLabel || "Academic Report");
      setReportConfig((current) => ({ ...current, reportTitle: suggestedTitle || "" }));
    }
    setIsReportConfigOpen(true);
  };

  const renderReportSelect = (label, field, options) => (
    <label className="block">
      <span className="text-xs font-semibold uppercase tracking-[0.18em] text-slate-400">{label}</span>
      <select
        value={reportConfig[field]}
        onChange={(event) => {
          const nextValue = event.target.value;
          const allowed = field === "wordCount"
            ? isReportWordCountAllowed(nextValue, reportConfig.customWordCount)
            : field === "reportDepth"
              ? isReportDepthAllowed(nextValue)
              : field === "academicLevel"
                ? isReportAcademicLevelAllowed(nextValue)
                : true;
          if (!allowed) {
            event.target.value = reportConfig[field];
            blockLockedPlanOption(`${label} ${nextValue}`, "a higher report plan");
            return;
          }
          updateReportConfigField(field, nextValue);
        }}
        className="mt-2 w-full rounded-2xl border border-white/10 bg-slate-950 px-4 py-3 text-sm text-white outline-none focus:border-emerald-300/60"
      >
        {options.map((option) => {
          const allowed = field === "wordCount"
            ? getCurrentPlanEntitlements().reportWordCounts.includes(option)
            : field === "reportDepth"
              ? isReportDepthAllowed(option)
              : field === "academicLevel"
                ? isReportAcademicLevelAllowed(option)
                : true;
          return <option key={option} value={option} disabled={!allowed}>{allowed ? option : `🔒 ${option}`}</option>;
        })}
      </select>
    </label>
  );

  const renderReportInput = (label, field, placeholder = "") => (
    <label className="block">
      <span className="text-xs font-semibold uppercase tracking-[0.18em] text-slate-400">{label}</span>
      <input
        value={reportConfig[field]}
        onChange={(event) => updateReportConfigField(field, event.target.value)}
        placeholder={placeholder}
        className="mt-2 w-full rounded-2xl border border-white/10 bg-slate-950 px-4 py-3 text-sm text-white outline-none placeholder:text-slate-500 focus:border-emerald-300/60"
      />
    </label>
  );

  const renderReportConfigurationPanel = () => (
    <div className="fixed inset-0 z-50 flex items-start justify-center overflow-y-auto bg-slate-950/85 px-4 py-6 backdrop-blur">
      <div className="w-full max-w-6xl rounded-[28px] border border-emerald-300/20 bg-slate-900 p-5 shadow-[0_30px_80px_rgba(0,0,0,0.45)] sm:p-6">
        <div className="flex flex-col gap-4 border-b border-white/10 pb-5 lg:flex-row lg:items-start lg:justify-between">
          <div>
            <p className="text-xs uppercase tracking-[0.28em] text-emerald-200/80">Report Configuration</p>
            <h3 className="mt-2 text-2xl font-semibold text-white">Ultra advanced AI report generator</h3>
          </div>
          <button type="button" onClick={() => setIsReportConfigOpen(false)} className="rounded-full border border-white/10 bg-white/5 px-4 py-2 text-sm font-semibold text-white">Close</button>
        </div>

        <div className="mt-6 grid gap-4 lg:grid-cols-3">
          <label className="block lg:col-span-3">
            <span className="text-xs font-semibold uppercase tracking-[0.18em] text-slate-400">Report Title Input</span>
            <input
              value={reportConfig.reportTitle}
              onChange={(event) => updateReportConfigField("reportTitle", event.target.value)}
              placeholder="Enter report topic..."
              className="mt-2 w-full rounded-2xl border border-emerald-300/20 bg-slate-950 px-4 py-4 text-base font-semibold text-white outline-none placeholder:text-slate-500 focus:border-emerald-300/70"
            />
          </label>
          {renderReportSelect("Academic Level", "academicLevel", reportAcademicLevels)}
          {renderReportSelect("Report Type", "reportType", reportTypes)}
          {renderReportSelect("Word Count", "wordCount", reportWordCounts)}
          {reportConfig.wordCount === "Custom" ? renderReportInput("Custom Word Count", "customWordCount", "e.g. 4200") : null}
          {renderReportSelect("Writing Style", "writingStyle", reportWritingStyles)}
          {renderReportSelect("Reference Style", "referenceStyle", reportReferenceStyles)}
          {renderReportSelect("Report Depth", "reportDepth", reportDepths)}
          {renderReportInput("Student Name", "studentName", "Optional")}
          {renderReportInput("Institution", "institution", "Optional")}
          {renderReportInput("Course", "course", "Optional")}
          {renderReportInput("Lecturer", "lecturer", "Optional")}
          <label className="block">
            <span className="text-xs font-semibold uppercase tracking-[0.18em] text-slate-400">Date</span>
            <input
              type="date"
              value={reportConfig.reportDate}
              onChange={(event) => updateReportConfigField("reportDate", event.target.value)}
              className="mt-2 w-full rounded-2xl border border-white/10 bg-slate-950 px-4 py-3 text-sm text-white outline-none focus:border-emerald-300/60"
            />
          </label>
        </div>

        <div className="mt-6 rounded-[24px] border border-white/10 bg-slate-950/70 p-4">
          <p className="text-xs font-semibold uppercase tracking-[0.2em] text-slate-400">AI Features Toggles</p>
          <div className="mt-4 grid gap-3 sm:grid-cols-2 lg:grid-cols-3">
            {reportFeatureToggles.map(([featureKey, label]) => {
              const allowed = isReportFeatureAllowed(featureKey);
              return (
              <label key={featureKey} onClick={(event) => {
                if (allowed) return;
                event.preventDefault();
                blockLockedPlanOption(label, "a higher report plan");
              }} className={`flex items-center gap-3 rounded-2xl border px-4 py-3 text-sm ${allowed ? "border-white/10 bg-white/[0.03] text-slate-100" : "cursor-pointer border-amber-300/20 bg-slate-950/80 text-slate-500"}`}>
                <input
                  type="checkbox"
                  checked={Boolean(reportConfig.features?.[featureKey])}
                  disabled={!allowed}
                  onChange={() => (allowed ? toggleReportFeature(featureKey) : blockLockedPlanOption(label, "a higher report plan"))}
                  className="h-4 w-4 accent-emerald-400"
                />
                <span>{allowed ? label : `🔒 ${label}`}</span>
              </label>
              );
            })}
          </div>
        </div>

        <div className="mt-6 flex flex-wrap justify-end gap-3">
          <button type="button" onClick={() => setIsReportConfigOpen(false)} className="rounded-full border border-white/10 bg-white/5 px-5 py-3 text-sm font-semibold text-white">Cancel</button>
          <button type="button" onClick={() => generateReport({ closePanel: true })} disabled={isGeneratingReport} className="rounded-full bg-[linear-gradient(135deg,#10b981,#059669)] px-5 py-3 text-sm font-semibold text-white disabled:opacity-50">{isGeneratingReport ? "Generating Now..." : reportData.body?.trim() ? "↻ Regenerate Now" : "Generate Now"}</button>
        </div>
      </div>
    </div>
  );

  const renderReportPanel = () => {
    const hasReport = Boolean(reportData && (reportData.body || "").trim());
    const getReportActionClassName = (label) => (
      label === "EXPAND REPORT"
        ? "rounded-full border border-emerald-300/35 bg-emerald-500 px-4 py-2 text-xs font-semibold uppercase tracking-[0.12em] text-white shadow-[0_10px_24px_rgba(16,185,129,0.24)] transition hover:bg-emerald-400 disabled:opacity-50"
        : "rounded-full border border-white/10 bg-white/5 px-4 py-2 text-xs font-semibold uppercase tracking-[0.12em] text-white transition hover:bg-white/10 disabled:opacity-50"
    );
    const reportActions = [
      ["EDIT REPORT", () => { setEditableReportBody(reportData.body || ""); setIsEditingReport(true); }],
      ["↻ REGENERATE", () => generateReport()],
      ["EXPORT PDF", downloadActiveContent],
      ["EXPORT DOCX", downloadReportDoc],
      ["EXPORT PPT", createPresentationFromReport],
      ["COPY TEXT", copyActiveContent],
      ["IMPROVE WRITING", () => refineReportWithPreset({ reportDepth: "Expert", writingStyle: "Analytical" })],
      ["HUMANIZE", () => refineReportWithPreset({ writingStyle: "Humanized Natural Style", features: { aiHumanizer: true } })],
      ["ADD REFERENCES", () => refineReportWithPreset({ features: { academicCitations: true } })],
      ["EXPAND REPORT", () => refineReportWithPreset({ wordCount: "5000+", reportDepth: "Research Intensive" })],
      ["SHORTEN REPORT", () => refineReportWithPreset({ wordCount: "1000", reportDepth: "Standard" })],
      ["CREATE PRESENTATION", createPresentationFromReport],
    ];

    return (
      <div className="space-y-5">
        {isReportConfigOpen ? renderReportConfigurationPanel() : null}
        <div className="rounded-[24px] border border-emerald-300/15 bg-[linear-gradient(180deg,rgba(6,95,70,0.08),rgba(6,12,10,0.9))] p-5">
          <div className="flex flex-col gap-5 lg:flex-row lg:items-start lg:justify-between">
            <div className="min-w-0">
              <p className="text-xs uppercase tracking-[0.3em] text-emerald-100/80">Academic Report</p>
              <h4 className="mt-2 text-3xl font-semibold text-white">Generate a structured academic report</h4>
              <p className="mt-3 max-w-3xl text-sm leading-7 text-slate-200">Open the advanced panel first, then generate a complete academic report with cover page, contents, analysis, recommendations, and references.</p>
            </div>
            <div className="force-mobile-stack flex flex-wrap gap-3">
              <button type="button" onClick={openReportConfiguration} disabled={isGeneratingReport} className="rounded-full bg-[linear-gradient(135deg,#10b981,#059669)] px-5 py-3 text-sm font-semibold text-white disabled:opacity-50">{isGeneratingReport ? "Generating Report..." : hasReport ? "↻ Regenerate Report" : "Generate Report"}</button>
              <button type="button" onClick={downloadActiveContent} disabled={!hasReport} className="rounded-full border border-emerald-300/20 bg-emerald-300/10 px-5 py-3 text-sm font-semibold text-emerald-50 disabled:opacity-50">Download Report</button>
            </div>
          </div>
        </div>

        {hasReport ? (
          <div className="space-y-4">
            <div className="flex flex-wrap gap-2">
              {reportActions.map(([label, handler]) => (
                <button key={label} type="button" onClick={handler} disabled={isGeneratingReport && label !== "COPY TEXT"} className={getReportActionClassName(label)}>{label}</button>
              ))}
            </div>
            {isEditingReport ? (
              <div className="rounded-[24px] border border-white/10 bg-slate-950/75 p-4">
                <textarea value={editableReportBody} onChange={(event) => setEditableReportBody(event.target.value)} className="min-h-[520px] w-full rounded-2xl border border-white/10 bg-slate-900 p-4 text-sm leading-7 text-white outline-none focus:border-emerald-300/60" />
                <div className="mt-3 flex flex-wrap justify-end gap-3">
                  <button type="button" onClick={() => setIsEditingReport(false)} className="rounded-full border border-white/10 bg-white/5 px-4 py-2 text-sm text-white">Cancel</button>
                  <button type="button" onClick={() => { setReportData((current) => ({ ...current, body: editableReportBody })); setIsEditingReport(false); setStatus("Report edits applied."); }} className="rounded-full bg-emerald-500 px-4 py-2 text-sm font-semibold text-white">Apply Edits</button>
                </div>
              </div>
            ) : (
              <article className="report-viewer mx-auto max-w-5xl rounded-[12px] bg-white p-6 text-black shadow-[0_24px_70px_rgba(0,0,0,0.28)] sm:p-10">
                <MobileFirstMarkdown>{reportData.body}</MobileFirstMarkdown>
              </article>
            )}
          </div>
        ) : (
          <div className="rounded-[24px] border border-dashed border-white/10 bg-white/[0.03] p-8 text-sm leading-7 text-slate-300">No academic report generated yet. Click Generate Report to open the configuration panel.</div>
        )}
      </div>
    );
  };

  const renderUpgradeModal = () => (
    <div className="fixed inset-0 z-[70] flex items-start justify-center overflow-y-auto bg-slate-950/80 px-4 py-6 backdrop-blur">
      <div className="w-full max-w-5xl rounded-[30px] border border-emerald-300/20 bg-[radial-gradient(circle_at_top,rgba(34,197,94,0.16),transparent_34%),linear-gradient(180deg,#0f172a,#020617)] p-5 text-white shadow-[0_30px_90px_rgba(0,0,0,0.5)] sm:p-6">
        <div className="flex flex-col gap-4 border-b border-white/10 pb-5 sm:flex-row sm:items-start sm:justify-between">
          <div>
            <p className="text-xs font-bold uppercase tracking-[0.3em] text-emerald-200/80">Upgrade</p>
            <h2 className="mt-2 text-3xl font-semibold tracking-[-0.03em] text-white">Subscribe with PayShap</h2>
            <p className="mt-3 max-w-3xl text-sm leading-7 text-slate-300">Choose a transparent plan and generate a unique PayShap reference. Your subscription activates only after an admin verifies the bank payment reference.</p>
          </div>
          <button type="button" onClick={() => { setIsUpgradeModalOpen(false); setBillingCheckoutMessage(""); setUpgradeLimitMessage(""); setBillingCheckoutPlanId(""); }} className="rounded-full border border-white/10 bg-white/5 px-4 py-2 text-sm font-semibold text-white transition hover:bg-white/10">Close</button>
        </div>
        {billingCheckoutMessage ? (
          <div className="mt-4 rounded-2xl border border-emerald-300/20 bg-emerald-300/10 px-4 py-3 text-sm font-semibold text-emerald-50">
            {billingCheckoutMessage}
          </div>
        ) : upgradeLimitMessage ? (
          <div className="mt-4 rounded-2xl border border-rose-300/25 bg-rose-500/10 px-4 py-3 text-sm font-semibold leading-7 text-rose-50">
            {renderCaptureErrorMessage(upgradeLimitMessage)}
          </div>
        ) : null}
        {manualPaymentRequest ? (
          <div className="mt-5">
            {renderPayShapInstructions(manualPaymentRequest)}
          </div>
        ) : manualPaymentDetails ? (
          <div className="mt-5 rounded-[24px] border border-white/10 bg-slate-950/60 p-4">
            <p className="text-xs font-bold uppercase tracking-[0.24em] text-slate-400">PayShap Account</p>
            <div className="mt-3 grid gap-3 sm:grid-cols-2">
              <div className="rounded-2xl border border-white/10 bg-white/[0.04] px-4 py-3 text-sm text-slate-200">PayShap Number: <span className="phone-safe-copy font-semibold text-white">{manualPaymentDetails.payshap_number || "Not configured"}</span></div>
              <div className="rounded-2xl border border-white/10 bg-white/[0.04] px-4 py-3 text-sm text-slate-200">Account Name: <span className="phone-safe-copy font-semibold text-white">{manualPaymentDetails.account_name || "Not configured"}</span></div>
            </div>
          </div>
        ) : null}
        <div className="mt-5 grid gap-4 lg:grid-cols-2">
          {fairSubscriptionPlans.map((plan) => (
            <article key={plan.name} className={`rounded-[24px] border p-5 ${plan.name === "Pro Student" || plan.name === "Premium Student" ? "border-emerald-300/30 bg-emerald-300/10" : "border-white/10 bg-white/[0.04]"}`}>
              <div className="flex items-start justify-between gap-3">
                <div>
                  <h3 className="text-xl font-semibold text-white">{plan.name}</h3>
                  <p className="mt-2 text-sm leading-6 text-slate-300">{plan.audience}</p>
                </div>
                <div className="text-right">
                  <span className="inline-flex rounded-full border border-emerald-300/20 bg-emerald-300/10 px-3 py-1 text-xs font-bold text-emerald-50">{plan.price}</span>
                  {plan.priceOptions ? <p className="mt-2 text-xs font-semibold text-emerald-100">{plan.priceOptions}</p> : null}
                </div>
              </div>
              <p className="mt-4 text-sm leading-7 text-slate-200">{plan.limits}</p>
              <div className="mt-4 rounded-2xl border border-white/10 bg-slate-950/45 p-4">
                <p className="text-xs font-bold uppercase tracking-[0.18em] text-emerald-100">How this plan works</p>
                <p className="mt-2 text-sm leading-6 text-slate-200">{plan.howItWorks}</p>
              </div>
              <div className="mt-3 rounded-2xl border border-white/10 bg-white/[0.04] p-4">
                <p className="text-xs font-bold uppercase tracking-[0.18em] text-slate-400">Daily attempts included</p>
                <div className="mt-3 grid gap-2 sm:grid-cols-2">
                  {plan.attempts.map((item) => (
                    <div key={`${plan.name}-${item}`} className="rounded-xl border border-white/10 bg-slate-950/55 px-3 py-2 text-xs font-semibold text-slate-200">{item}</div>
                  ))}
                </div>
              </div>
              <div className="mt-4 flex flex-wrap gap-2">
                {plan.safeguards.map((item) => <span key={`${plan.name}-${item}`} className="rounded-full border border-white/10 bg-slate-950/60 px-3 py-1 text-xs text-slate-200">{item}</span>)}
              </div>
              {plan.billingOptions?.length ? (
                <div className="mt-5 grid gap-2 sm:grid-cols-3">
                  {plan.billingOptions.map((option) => (
                    <button
                      key={option.id}
                      type="button"
                      onClick={() => startBillingCheckout({ ...plan, id: option.id })}
                      disabled={Boolean(billingCheckoutPlanId)}
                      className="rounded-2xl bg-white px-3 py-3 text-xs font-bold text-slate-950 transition hover:bg-emerald-50 disabled:cursor-wait disabled:opacity-70"
                    >
                      {billingCheckoutPlanId === option.id ? "Generating..." : `${option.label} ${option.price}`}
                    </button>
                  ))}
                </div>
              ) : (
                <button type="button" onClick={() => startBillingCheckout(plan)} disabled={Boolean(billingCheckoutPlanId)} className="mt-5 w-full rounded-full bg-white px-4 py-3 text-sm font-bold text-slate-950 transition hover:bg-emerald-50 disabled:cursor-wait disabled:opacity-70">
                  {billingCheckoutPlanId === plan.id ? "Generating..." : plan.paymentType === "free" ? "Start Free" : plan.paymentType === "quote" ? "Request Quote" : "Generate PayShap Reference"}
                </button>
              )}
            </article>
          ))}
        </div>
        {(paymentRequests.length || manualPaymentRequest) ? (
          <div className="mt-5 rounded-[24px] border border-white/10 bg-slate-950/60 p-4">
            <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
              <div>
                <p className="text-xs font-bold uppercase tracking-[0.24em] text-slate-400">My Payments</p>
                <p className="mt-2 text-sm text-slate-300">Pending payments wait for admin verification before plan activation.</p>
              </div>
              <button type="button" onClick={() => { setIsUpgradeModalOpen(false); openProtectedAppPage("payments"); }} className="rounded-full border border-white/10 bg-white/5 px-4 py-2 text-xs font-bold text-white">Open Page</button>
            </div>
            <div className="mt-4">{renderPaymentRequestsTable(paymentRequests, { compact: true })}</div>
          </div>
        ) : null}
        <div className="mt-5 rounded-[24px] border border-white/10 bg-slate-950/60 p-4">
          <p className="text-xs font-bold uppercase tracking-[0.24em] text-slate-400">Billing protection</p>
          <div className="mt-3 grid gap-2 sm:grid-cols-2">
            {fairBillingGuardrails.map((rule) => <div key={rule} className="rounded-2xl border border-white/10 bg-white/[0.04] px-4 py-3 text-sm text-slate-200">{rule}</div>)}
          </div>
        </div>
        {billingSubscription ? (
          <div className="mt-5 rounded-[24px] border border-white/10 bg-slate-950/60 p-4">
            <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
              <div>
                <p className="text-xs font-bold uppercase tracking-[0.24em] text-slate-400">Current Subscription Period</p>
                <p className="mt-2 text-sm leading-6 text-slate-300">
                  Plan: {(billingSubscription.plan_id || "free").replaceAll("_", " ")}
                  {billingSubscription.current_period_end ? ` · Ends ${formatAdminDateTime(billingSubscription.current_period_end)}` : ""}
                </p>
              </div>
              <span className={`rounded-full px-4 py-2 text-xs font-bold uppercase tracking-[0.16em] ${billingSubscription.active ? "bg-emerald-300/10 text-emerald-100" : "bg-slate-800 text-slate-300"}`}>
                {getSubscriptionCountdownText(billingSubscription) || "Free Plan"}
              </span>
            </div>
            {billingSubscription.message ? <p className="mt-3 rounded-2xl border border-amber-300/20 bg-amber-300/10 px-4 py-3 text-sm text-amber-50">{billingSubscription.message}</p> : null}
          </div>
        ) : null}
        {billingUsage?.features?.length ? (
          <div className="mt-5 rounded-[24px] border border-white/10 bg-slate-950/60 p-4">
            <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
              <div>
                  <p className="text-xs font-bold uppercase tracking-[0.24em] text-slate-400">Attempts Remaining Today</p>
                <p className="mt-2 text-sm text-slate-300">
                  Current plan: {(billingUsage.plan_id || billingSubscription?.plan_id || "free").replaceAll("_", " ")} · Daily period: {billingUsage.period_key || "today"}
                  {billingUsage.reset_label ? ` · Resets ${billingUsage.reset_label}` : ""}
                </p>
              </div>
              <button type="button" onClick={() => refreshBillingStatus().catch((err) => setBillingCheckoutMessage(getReadableRequestError(err)))} disabled={isBillingUsageLoading} className="rounded-full border border-white/10 bg-white/5 px-4 py-2 text-xs font-bold text-white transition hover:bg-white/10 disabled:cursor-wait disabled:opacity-70">{isBillingUsageLoading ? "Refreshing..." : "Refresh Usage"}</button>
            </div>
            <div className="mt-4 grid gap-2 sm:grid-cols-2 lg:grid-cols-3">
              {billingUsage.features.map((feature) => (
                <div key={feature.feature} className="rounded-2xl border border-white/10 bg-white/[0.04] px-4 py-3">
                  <div className="flex items-center justify-between gap-3 text-sm">
                    <span className="font-semibold text-white">{feature.label}</span>
                    <span className="text-emerald-100">{feature.unlimited ? "Unlimited" : `${feature.remaining} left today`}</span>
                  </div>
                  <div className="mt-2 h-2 overflow-hidden rounded-full bg-white/10">
                    <div className="h-full rounded-full bg-emerald-400" style={{ width: `${feature.unlimited ? 100 : Math.min(100, Math.round((Number(feature.used || 0) / Math.max(1, Number(feature.limit || 1))) * 100))}%` }} />
                  </div>
                  <p className="mt-2 text-xs text-slate-400">{feature.unlimited ? "Unlimited access" : `${feature.used || 0}/${feature.limit || 0} used today${feature.reset_label ? ` · resets ${feature.reset_label}` : ""}`}</p>
                </div>
              ))}
            </div>
          </div>
        ) : (
          <div className="mt-5 rounded-[24px] border border-white/10 bg-slate-950/60 p-4">
            <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
              <div>
                <p className="text-xs font-bold uppercase tracking-[0.24em] text-slate-400">Attempts Remaining Today</p>
                <p className="mt-2 text-sm leading-6 text-slate-300">
                  {!authToken
                    ? "Sign in to load your account-based usage meter."
                    : isBillingUsageLoading
                      ? "Loading your remaining attempts from the backend..."
                      : "Usage meter is not loaded yet. Refresh to fetch your remaining attempts for this email."}
                </p>
              </div>
              <button type="button" onClick={() => refreshBillingStatus().catch((err) => setBillingCheckoutMessage(getReadableRequestError(err)))} disabled={!authToken || isBillingUsageLoading} className="rounded-full border border-white/10 bg-white/5 px-4 py-2 text-xs font-bold text-white transition hover:bg-white/10 disabled:cursor-not-allowed disabled:opacity-60">{isBillingUsageLoading ? "Loading..." : "Refresh Usage"}</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );

  const renderMindMapPanel = () => {
    const hasMindMap = Boolean(mindMapData.root);
    const selectedNode = selectedMindMapNode || mindMapData.root;
    const flattenedNodes = flattenMindMapNodes(mindMapData.root);
    return (
      <div className="space-y-5">
        <div className="rounded-[24px] border border-white/10 bg-white p-5 text-slate-950 shadow-[0_22px_55px_rgba(15,23,42,0.14)]">
          <div className="flex flex-col gap-5 lg:flex-row lg:items-start lg:justify-between">
            <div className="min-w-0">
              <p className="text-xs font-bold uppercase tracking-[0.28em] text-emerald-700">Mind Map Generator</p>
              <h4 className="mt-2 text-3xl font-semibold text-slate-950">Build an interactive knowledge graph</h4>
              <p className="mt-3 max-w-3xl text-sm leading-7 text-slate-600">Detects concepts, hierarchy, relationships, definitions, formulas, examples, processes, and source locations from your study material.</p>
            </div>
            <div className="force-mobile-stack flex flex-wrap gap-3">
              <button type="button" onClick={generateMindMap} disabled={isGeneratingMindMap} className="rounded-full bg-white px-5 py-3 text-sm font-bold text-black shadow-[0_12px_30px_rgba(15,23,42,0.16)] ring-1 ring-slate-200 transition hover:-translate-y-0.5 hover:shadow-[0_16px_34px_rgba(15,23,42,0.22)] disabled:translate-y-0 disabled:opacity-50">{isGeneratingMindMap ? "Generating Mind Map..." : hasMindMap ? "↻ Regenerate Mind Map" : "Generate Mind Map"}</button>
              <button type="button" onClick={downloadMindMapJson} disabled={!hasMindMap} className="rounded-full border border-slate-200 bg-slate-950 px-5 py-3 text-sm font-semibold text-white disabled:opacity-50">Export JSON</button>
            </div>
          </div>
          <div className="mt-5 grid gap-4 md:grid-cols-[minmax(0,1fr)_220px]">
            <label className="block">
              <span className="text-xs font-bold uppercase tracking-[0.18em] text-slate-500">Central topic hint</span>
              <input value={mindMapTopic} onChange={(event) => setMindMapTopic(event.target.value)} placeholder="Optional topic, e.g. Signal Processing" className="mt-2 w-full rounded-2xl border border-slate-200 bg-white px-4 py-3 text-sm text-slate-950 outline-none focus:border-emerald-500" />
            </label>
            <label className="block">
              <span className="text-xs font-bold uppercase tracking-[0.18em] text-slate-500">Depth level</span>
              <select value={mindMapDepth} onChange={(event) => {
                const nextDepth = event.target.value;
                if (!isMindMapDepthAllowed(nextDepth)) {
                  event.target.value = mindMapDepth;
                  blockLockedPlanOption(`Mind map ${nextDepth} depth`, nextDepth === "Research" ? "Premium" : "Pro");
                  return;
                }
                setMindMapDepth(nextDepth);
              }} className="mt-2 w-full rounded-2xl border border-slate-200 bg-white px-4 py-3 text-sm text-slate-950 outline-none focus:border-emerald-500">
                {mindMapDepthOptions.map((option) => {
                  const allowed = isMindMapDepthAllowed(option);
                  return <option key={option} value={option} disabled={!allowed}>{allowed ? option : `🔒 ${option}`}</option>;
                })}
              </select>
            </label>
          </div>
          <div className="mt-4 flex flex-wrap gap-2 text-xs font-semibold text-slate-600">
            {mindMapDepthOptions.map((option) => {
              const allowed = isMindMapDepthAllowed(option);
              return (
                <button key={option} type="button" onClick={() => (allowed ? setMindMapDepth(option) : blockLockedPlanOption(`Mind map ${option} depth`, option === "Research" ? "Premium" : "Pro"))} className={`rounded-full border px-3 py-2 ${mindMapDepth === option ? "border-emerald-600 bg-emerald-50 text-emerald-800" : allowed ? "border-slate-200 bg-white text-slate-600" : "border-amber-200 bg-slate-100 text-slate-400"}`}>{allowed ? option : `🔒 ${option}`}</button>
              );
            })}
          </div>
        </div>

        {hasMindMap ? (
          <div className="grid gap-5 xl:grid-cols-[minmax(0,1fr)_340px]">
            <div ref={mindMapExportRef} className="min-w-0 rounded-[28px] border border-white/10 bg-slate-100 p-4">
              <div className="mb-4 flex flex-wrap items-center justify-between gap-3">
                <div>
                  <p className="text-xs font-bold uppercase tracking-[0.24em] text-slate-500">Interactive Graph</p>
                  <h4 className="mt-1 text-xl font-semibold text-slate-950">{mindMapData.title || mindMapData.root?.title || "Mind Map"}</h4>
                </div>
                <div className="flex flex-wrap gap-2">
                  <button type="button" onClick={openMindMapFullscreen} className="rounded-full border border-slate-200 bg-white px-3 py-2 text-xs font-bold text-slate-800">Fullscreen</button>
                  {isMindMapFullscreen ? <button type="button" onClick={closeMindMapFullscreen} className="rounded-full border border-emerald-200 bg-emerald-600 px-3 py-2 text-xs font-bold text-white">Minimize</button> : null}
                  <button type="button" onClick={generateMindMap} disabled={isGeneratingMindMap} className="rounded-full border border-emerald-200 bg-emerald-600 px-3 py-2 text-xs font-bold text-white disabled:opacity-50">{isGeneratingMindMap ? "Generating..." : "↻ Regenerate"}</button>
                  <button type="button" onClick={downloadMindMapPng} className="rounded-full border border-slate-200 bg-white px-3 py-2 text-xs font-bold text-slate-800">PNG</button>
                  <button type="button" onClick={downloadMindMapSvg} className="rounded-full border border-slate-200 bg-white px-3 py-2 text-xs font-bold text-slate-800">SVG</button>
                  <button type="button" onClick={downloadMindMapPdf} className="rounded-full border border-slate-200 bg-white px-3 py-2 text-xs font-bold text-slate-800">PDF</button>
                </div>
              </div>
              <div ref={mindMapCanvasRef}>
                <MindMapFlow root={mindMapData.root} onSelectNode={setSelectedMindMapNode} />
              </div>
              <div
                ref={mindMapFullExportRef}
                aria-hidden="true"
                className="pointer-events-none fixed -left-[10000px] top-0 w-[2400px] bg-white p-4"
              >
                <MindMapFlow root={mindMapData.root} exportMode />
              </div>
            </div>

            <aside className="rounded-[28px] border border-white/10 bg-slate-950 p-5 text-white">
              <p className="text-xs font-bold uppercase tracking-[0.24em] text-emerald-200/80">Node Inspector</p>
              {selectedNode ? (
                <div className="mt-4 space-y-4">
                  <div>
                    <h4 className="text-2xl font-semibold">{selectedNode.title || selectedNode.label}</h4>
                    <p className="mt-2 text-xs uppercase tracking-[0.18em] text-slate-400">{selectedNode.type || "Concept"}</p>
                  </div>
                  <div className="rounded-2xl border border-white/10 bg-white/[0.04] p-4">
                    <p className="text-xs uppercase tracking-[0.2em] text-slate-400">Detailed Explanation</p>
                    <p className="mt-2 text-sm leading-7 text-slate-200">{selectedNode.summary || "No explanation available yet."}</p>
                  </div>
                  <div className="grid gap-3 sm:grid-cols-2 xl:grid-cols-1">
                    <div className="rounded-2xl border border-white/10 bg-white/[0.04] p-4"><p className="text-xs uppercase tracking-[0.18em] text-slate-400">Importance</p><p className="mt-2 text-lg font-semibold">{selectedNode.importance || selectedNode.importance_score || 0}/100</p></div>
                    <div className="rounded-2xl border border-white/10 bg-white/[0.04] p-4"><p className="text-xs uppercase tracking-[0.18em] text-slate-400">Source Location</p><p className="mt-2 text-sm leading-6 text-slate-200">{selectedNode.source_location || "Source material"}</p></div>
                  </div>
                  <div className="rounded-2xl border border-white/10 bg-white/[0.04] p-4">
                    <p className="text-xs uppercase tracking-[0.18em] text-slate-400">Connected Topics</p>
                    <div className="mt-3 flex flex-wrap gap-2">{(selectedNode.connected_topics || []).length ? selectedNode.connected_topics.map((topic) => <span key={topic} className="rounded-full bg-white/10 px-3 py-1 text-xs text-slate-100">{topic}</span>) : <span className="text-sm text-slate-400">No explicit links listed.</span>}</div>
                  </div>
                  <div className="rounded-2xl border border-white/10 bg-white/[0.04] p-4">
                    <p className="text-xs uppercase tracking-[0.18em] text-slate-400">Map Stats</p>
                    <p className="mt-2 text-sm leading-7 text-slate-200">{mindMapData.nodeCount || flattenedNodes.length} nodes • {mindMapData.depth || mindMapDepth} depth</p>
                  </div>
                </div>
              ) : (
                <p className="mt-4 text-sm leading-7 text-slate-300">Click a node to inspect its explanation, source location, importance, and connected topics.</p>
              )}
            </aside>
          </div>
        ) : (
          <div className="rounded-[24px] border border-dashed border-white/10 bg-white/[0.03] p-8 text-sm leading-7 text-slate-300">No mind map generated yet. Add material or enter a topic, then click Generate Mind Map.</div>
        )}
      </div>
    );
  };

  const openProtectedAppPage = (pageId, { replace = false } = {}) => {
    const normalizedPageId = normalizeAppPageId(pageId, "capture");
    if (!authToken) {
      currentPageRef.current = normalizedPageId;
      setCurrentPage(normalizedPageId);
      return;
    }
    const targetRoute = resolveAppRouteForPage(normalizedPageId, authSessionMode);
    if (targetRoute && browserPath === targetRoute && currentPageRef.current === normalizedPageId) return;
    currentPageRef.current = normalizedPageId;
    setCurrentPage(normalizedPageId);
    if (targetRoute) navigateToPath(targetRoute, { replace });
  };

  const openModeSelection = ({ replace = false } = {}) => {
    currentPageRef.current = "mode-select";
    setCurrentPage("mode-select");
    navigateToPath("/", { replace });
  };

  const revealWorkspacePage = (tabId = "guide", { forcePage = false } = {}) => {
    const normalizedTabId = normalizeWorkspaceTabId(tabId || "guide");
    setActiveTab(normalizedTabId);
    if (forcePage || !["materials", "payments", "timetable", "about", "support", "voice"].includes(currentPageRef.current)) {
      openProtectedAppPage("workspace");
    }
  };

  const focusRoomReplyComposer = () => {
    if (typeof window === "undefined") return;
    const focusInput = () => {
      if (!roomMessageInputRef.current) return;
      roomMessageInputRef.current.focus();
      const valueLength = roomMessageInputRef.current.value?.length || 0;
      if (typeof roomMessageInputRef.current.setSelectionRange === "function") {
        roomMessageInputRef.current.setSelectionRange(valueLength, valueLength);
      }
    };
    window.requestAnimationFrame(focusInput);
    window.setTimeout(focusInput, 120);
    window.setTimeout(focusInput, 260);
  };

  const ensureCollaborationNotificationPermission = async ({ promptIfNeeded = false } = {}) => {
    if (typeof window === "undefined" || typeof Notification === "undefined") return "unsupported";
    if (Notification.permission === "granted" || Notification.permission === "denied") return Notification.permission;
    if (!promptIfNeeded) return Notification.permission;
    try {
      return await Notification.requestPermission();
    } catch {
      return Notification.permission || "default";
    }
  };

  const showCollaborationSystemNotification = async (notificationPayload) => {
    if (
      typeof window === "undefined"
      || typeof Notification === "undefined"
      || Notification.permission !== "granted"
      || !notificationPayload?.roomId
    ) {
      return;
    }

    const roomId = normalizeCollaborationRoomId(notificationPayload.roomId);
    if (!roomId) return;

    const title = truncatePreviewText(notificationPayload.roomTitle || "New study room message", 64);
    const body = truncatePreviewText(
      `${notificationPayload.authorEmail || "A collaborator"}: ${notificationPayload.content || ""}`.trim(),
      140,
    );
    const url = `${window.location.origin}${buildCollaborationReplyPath(roomId)}`;
    const notificationOptions = {
      body,
      tag: `collaboration-room-${roomId}`,
      renotify: true,
      icon: `${window.location.origin}/mabaso-og.png`,
      badge: `${window.location.origin}/mabaso-og.png`,
      data: { roomId, url },
    };

    try {
      if ("serviceWorker" in navigator) {
        const registration = await navigator.serviceWorker.ready;
        await registration.showNotification(title, notificationOptions);
        return;
      }
    } catch {
      // Fall back to the page Notification API below.
    }

    try {
      const notification = new Notification(title, notificationOptions);
      notification.onclick = () => {
        window.focus();
        void openCollaborationReplyComposer(roomId);
        notification.close();
      };
    } catch {
      // Ignore browser notification failures and keep the in-app prompt path available.
    }
  };

  const handleCollaborationRoomActivity = (rooms = []) => {
    const nextRooms = Array.isArray(rooms) ? rooms.filter((room) => room && room.id) : [];
    const trackedMessageIds = collaborationRoomMessageIdsRef.current;
    const normalizedCurrentUserEmail = normalizeHistoryOwnerEmail(authEmail || authEmailInput || "");
    const collaborationSurfaceActive = currentPage === "collaboration" || (currentPage === "workspace" && activeTab === "collaboration");
    let newestIncomingMessage = null;

    nextRooms.forEach((room) => {
      const latestMessage = getLatestCollaborationRoomMessageRecord(room);
      const nextMessageId = latestMessage?.id || "";
      const previousMessageId = Object.prototype.hasOwnProperty.call(trackedMessageIds, room.id)
        ? trackedMessageIds[room.id]
        : undefined;

      trackedMessageIds[room.id] = nextMessageId;

      if (!latestMessage || previousMessageId === undefined || previousMessageId === nextMessageId) return;
      if (normalizeHistoryOwnerEmail(latestMessage.author_email || "") === normalizedCurrentUserEmail) return;

      const candidate = {
        roomId: room.id,
        roomTitle: room.title || "Study room",
        messageId: latestMessage.id,
        authorEmail: latestMessage.author_email || "",
        content: latestMessage.content || "",
        createdAt: latestMessage.created_at || "",
      };

      if (
        !newestIncomingMessage
        || new Date(candidate.createdAt || 0).getTime() >= new Date(newestIncomingMessage.createdAt || 0).getTime()
      ) {
        newestIncomingMessage = candidate;
      }
    });

    if (!newestIncomingMessage) return;

    if (collaborationSurfaceActive) {
      setCollaborationMessagePrompt(newestIncomingMessage);
    }

    if (!collaborationSurfaceActive || document.visibilityState === "hidden") {
      void showCollaborationSystemNotification(newestIncomingMessage);
    }
  };

  const openCollaborationReplyComposer = async (roomId) => {
    const normalizedRoomId = normalizeCollaborationRoomId(roomId);
    if (!normalizedRoomId) return;

    pendingCollaborationReplyRoomIdRef.current = normalizedRoomId;
    setCollaborationMessagePrompt(null);

    if (!authToken) {
      persistPendingRoomInviteId(normalizedRoomId);
      persistPostAuthRedirectPath("/app/collaboration");
      navigateToPath("/");
      return;
    }

    openCollaborationPage({ refresh: false, promptNotifications: false });
    await loadCollaborationRoom(normalizedRoomId, { resetNotesDraft: true });
    focusRoomReplyComposer();
  };

  const openCollaborationPage = ({ replace = false, refresh = true, promptNotifications = true } = {}) => {
    if (promptNotifications) {
      void ensureCollaborationNotificationPermission({ promptIfNeeded: true });
    }
    openProtectedAppPage("collaboration", { replace });
    if (refresh) refreshCollaborationRooms(true);
  };

  useEffect(() => {
    if (typeof window === "undefined") return undefined;

    const handlePopState = () => {
      const nextPath = resolveBrowserPath();
      setBrowserPath(nextPath);
      setPublicPage(nextPath === PUBLIC_TERMS_PATH ? "terms" : "auth");
    };

    window.addEventListener("popstate", handlePopState);
    return () => window.removeEventListener("popstate", handlePopState);
  }, []);

  useEffect(() => {
    currentPageRef.current = currentPage;
  }, [currentPage]);

  useEffect(() => {
    const nextInviteRoomId = parseRoomInviteIdFromLocation();
    if (!nextInviteRoomId) return;
    persistPendingRoomInviteId(nextInviteRoomId);
    setHighlightedInviteRoomId((current) => current || nextInviteRoomId);
  }, [browserPath]);

  useEffect(() => {
    if (!authToken) return;
    setPublicPage("auth");
    setShowLandingAuthOptions(false);
  }, [authToken]);

  useEffect(() => {
    if (!showLandingAuthOptions || typeof window === "undefined") return;
    window.requestAnimationFrame(() => {
      landingAuthPanelRef.current?.scrollIntoView?.({ block: "start", inline: "nearest" });
    });
  }, [showLandingAuthOptions]);

  useEffect(() => {
    if (!authChecked || authToken || !findProtectedWorkspaceRoute(browserPath)) return;
    const explicitPreviewPath = consumeExplicitProtectedPreviewPath();
    if (explicitPreviewPath === browserPath) return;
    navigateToPath("/", { replace: true });
  }, [authChecked, authToken, browserPath]);

  useEffect(() => {
    setDismissedRoomInviteIds(loadDismissedRoomInviteIds(authEmail || authEmailInput || ""));
  }, [authEmail, authEmailInput]);

  useEffect(() => {
    if (supportContactEmail.trim()) return;
    const fallbackEmail = authEmail || authEmailInput || "";
    if (fallbackEmail) setSupportContactEmail(fallbackEmail);
  }, [authEmail, authEmailInput, supportContactEmail]);

  useEffect(() => {
    if (!supportContactDevice.trim()) {
      setSupportContactDevice(detectSupportDevice());
    }
    if (!supportContactBrowser.trim()) {
      setSupportContactBrowser(detectSupportBrowser());
    }
  }, [supportContactBrowser, supportContactDevice]);

  useEffect(() => {
    roomSharedNotesDraftRef.current = roomSharedNotesDraft;
  }, [roomSharedNotesDraft]);

  const openPublicTermsPage = () => navigateToPath("/company/terms");

  const closePublicTermsPage = () => navigateToPath("/");

  const lectureNotes = studySourceEntriesToText(lectureNoteSources, "LECTURE NOTE");
