    const teacherRealtimeProfileLabel = teacherRealtimeProfile === "deep_explain" ? "Deep Explain" : "Smart Saver";
    const realtimeStatusLabel = teacherRealtimeConnectionState === TEACHER_REALTIME_CONNECTION_STATES.CONNECTED
